import { useState } from "react";
import { createPortal } from "react-dom";
import { logo } from "../../assets/images";
import styles from "./layout.module.scss"; 

export default function Header() {
  const headerRoot = document.getElementById("header");
  if (!headerRoot) return null;

  const [selectedLang, setSelectedLang] = useState("KO");
  const [menuOpen, setMenuOpen] = useState(false);

  return createPortal(
    <div className={styles.headerInner}>
      <ul>
        <li
          className={`hoverEffect ${selectedLang === "KO" ? styles.current : ""}`}
          onClick={() => setSelectedLang("KO")}
        >
          KO
        </li>
        <li>|</li>
        <li
          className={`hoverEffect ${selectedLang === "EN" ? styles.current : ""}`}
          onClick={() => setSelectedLang("EN")}
        >
          EN
        </li>
      </ul>

      <a href="/">
        <img src={logo} alt="Logo" />
      </a>

      <nav>
        <button  type="button" className={`${styles.menuButton} ${menuOpen ? styles.open : ""}`} onClick={() => setMenuOpen(!menuOpen)}>
          <span></span>
          <span></span>
          <span></span>
        </button>
        <ol className={menuOpen ? styles.open : ""}>
          <li><a className="hoverEffect" href="/">HOME</a></li>
          <li><a className="hoverEffect" href="#profile">PROFILE</a></li>
          <li><a className="hoverEffect" href="#projects">PROJECTS</a></li>
          <li><a className="hoverEffect" href="#contact">CONTACT</a></li>
        </ol>
      </nav>
    </div>,
    headerRoot
  );
}
